45→/// Shared HTTP client for LLM providers.
46→///
47→/// All providers that don't need custom redirect/proxy settings should
48→/// reuse this client to share connection pools, DNS cache, and TLS sessions.
49→pub fn shared_http_client() -> &'static reqwest::Client {
50→    static CLIENT: std::sync::LazyLock<reqwest::Client> =
