83→const MODEL_ID_NAMESPACE_SEP: &str = "::";
84→
85→#[must_use]
86→pub fn namespaced_model_id(provider: &str, model_id: &str) -> String {
87→    if model_id.contains(MODEL_ID_NAMESPACE_SEP) {
88→        return model_id.to_string();
89→    }
90→    format!("{provider}{MODEL_ID_NAMESPACE_SEP}{model_id}")
91→}
92→
93→/// Separator between a model ID and its reasoning effort suffix.
94→const REASONING_SUFFIX_SEP: char = '@';
95→
96→/// Reasoning effort suffixes appended to model IDs.
97→const REASONING_SUFFIXES: &[(&str, moltis_agents::model::ReasoningEffort)] = &[
98→    ("reasoning-low", moltis_agents::model::ReasoningEffort::Low),
99→    (

100→    (
101→        "reasoning-medium",
102→        moltis_agents::model::ReasoningEffort::Medium,
103→    ),
104→    (
105→        "reasoning-high",
106→        moltis_agents::model::ReasoningEffort::High,
107→    ),
108→];
109→
110→/// Split a model ID into (base_id, optional reasoning effort).
111→///
112→/// Examples:
113→/// - `"anthropic::claude-opus-4-5@reasoning-high"` → `("anthropic::claude-opus-4-5", Some(High))`
114→/// - `"gpt-4o"` → `("gpt-4o", None)`
115→#[must_use]
116→pub fn split_reasoning_suffix(
117→    model_id: &str,
118→) -> (&str, Option<moltis_agents::model::ReasoningEffort>) {
119→    if let Some((base, suffix)) = model_id.rsplit_once(REASONING_SUFFIX_SEP) {
120→        for &(tag, effort) in REASONING_SUFFIXES {
121→            if suffix == tag {
122→                return (base, Some(effort));
123→            }
124→        }
125→    }
126→    (model_id, None)
127→}
128→
129→#[must_use]
130→pub fn raw_model_id(model_id: &str) -> &str {
131→    // Fast path: skip reasoning suffix parsing when no `@` is present.
132→    let base = if model_id.contains(REASONING_SUFFIX_SEP) {
133→        split_reasoning_suffix(model_id).0
134→    } else {
135→        model_id
136→    };
137→    base.rsplit_once(MODEL_ID_NAMESPACE_SEP)
138→        .map(|(_, raw)| raw)
139→        .unwrap_or(base)
140→}
141→
142→#[must_use]
143→fn capability_model_id(model_id: &str) -> &str {
144→    let raw = raw_model_id(model_id).trim();
145→    raw.rsplit('/')
146→        .next()
147→        .filter(|id| !id.is_empty())
148→        .unwrap_or(raw)
149→}
