184→fn normalize_unique_models(models: impl IntoIterator<Item = String>) -> Vec<String> {
185→    let mut normalized_models = Vec::new();
186→    let mut seen = HashSet::new();
187→    for model in models {
188→        let normalized = model.trim().to_string();
189→        if normalized.is_empty() || !seen.insert(normalized.clone()) {
190→            continue;
191→        }
192→        normalized_models.push(normalized);
193→    }
194→    normalized_models
195→}
