201→fn merge_preferred_and_discovered_models(
202→    preferred: Vec<String>,
203→    discovered: Vec<DiscoveredModel>,
204→) -> Vec<DiscoveredModel> {
205→    let discovered_by_id: HashMap<String, &DiscoveredModel> =
206→        discovered.iter().map(|m| (m.id.clone(), m)).collect();
207→    let mut merged = Vec::new();
208→    let mut seen = HashSet::new();
209→
210→    for model_id in preferred {
211→        if !seen.insert(model_id.clone()) {
212→            continue;
213→        }
214→        let model = if let Some(d) = discovered_by_id.get(&model_id) {
215→            DiscoveredModel {
216→                id: model_id,
217→                display_name: d.display_name.clone(),
218→                created_at: d.created_at,
219→            }
220→        } else {
221→            DiscoveredModel::new(model_id.clone(), model_id)
222→        };
223→        merged.push(model);
224→    }
225→
226→    for model in discovered {
227→        if !seen.insert(model.id.clone()) {
228→            continue;
229→        }
230→        merged.push(model);
231→    }
232→
233→    merged
234→}
235→
236→fn merge_discovered_with_fallback_catalog(
237→    discovered: Vec<DiscoveredModel>,
238→    fallback: Vec<DiscoveredModel>,
239→) -> Vec<DiscoveredModel> {
240→    if discovered.is_empty() {
241→        return fallback;
242→    }
243→
244→    let fallback_by_id: HashMap<String, DiscoveredModel> =
245→        fallback.into_iter().map(|m| (m.id.clone(), m)).collect();
246→    discovered
247→        .into_iter()
248→        .map(|m| {
249→            let display_name = if m.display_name.trim().is_empty() {

250→                fallback_by_id
251→                    .get(&m.id)
252→                    .map(|fb| fb.display_name.clone())
253→                    .unwrap_or_else(|| m.id.clone())
254→            } else {
255→                m.display_name
256→            };
257→            DiscoveredModel {
258→                id: m.id,
259→                display_name,
260→                created_at: m.created_at,
261→            }
262→        })
263→        .collect()
264→}
