271→/// Parse `Retry-After` header as milliseconds.
272→///
273→/// `Retry-After` may be either delta-seconds or an HTTP date. We currently
274→/// consume delta-seconds, which is what providers typically return for 429.
275→pub(crate) fn retry_after_ms_from_headers(headers: &reqwest::header::HeaderMap) -> Option<u64> {
276→    let value = headers.get(reqwest::header::RETRY_AFTER)?;
277→    let text = value.to_str().ok()?.trim();
278→    let seconds = text.parse::<u64>().ok()?;
279→    seconds.checked_mul(1_000)
280→}
281→
282→/// Attach an explicit retry hint marker consumable by runner retry logic.
283→pub(crate) fn with_retry_after_marker(base: String, retry_after_ms: Option<u64>) -> String {
284→    match retry_after_ms {
285→        Some(ms) => format!("{base} (retry_after_ms={ms})"),
286→        None => base,
287→    }
288→}
