290→#[derive(Debug, serde::Deserialize)]
291→struct OllamaTagEntry {
292→    name: String,
293→}
294→
295→#[derive(Debug, serde::Deserialize)]
296→struct OllamaTagsPayload {
297→    #[serde(default)]
298→    models: Vec<OllamaTagEntry>,
299→}
300→
301→async fn discover_ollama_models_from_api(base_url: String) -> anyhow::Result<Vec<DiscoveredModel>> {
302→    let api_base = normalize_ollama_api_base_url(&base_url);
303→    let endpoint = format!("{}/api/tags", api_base.trim_end_matches('/'));
304→    let response = reqwest::Client::builder()
305→        .timeout(std::time::Duration::from_secs(2))
306→        .build()?
307→        .get(&endpoint)
308→        .send()
309→        .await?;
310→
311→    let status = response.status();
312→    if !status.is_success() {
313→        anyhow::bail!("ollama model discovery failed HTTP {status}");
314→    }
315→
316→    let payload: OllamaTagsPayload = response.json().await?;
317→    let mut models: Vec<DiscoveredModel> = payload
318→        .models
319→        .into_iter()
320→        .map(|entry| entry.name.trim().to_string())
321→        .filter(|model| !model.is_empty())
322→        .map(|model| DiscoveredModel::new(model.clone(), model))
323→        .collect();
324→    models.sort_by(|left, right| left.id.cmp(&right.id));
325→    models.dedup_by(|left, right| left.id == right.id);
326→    Ok(models)
327→}
328→
329→/// Spawn Ollama model discovery in a background thread and return the receiver
330→/// immediately, without blocking. Call `.recv()` later to collect the result.
331→fn start_ollama_discovery(
332→    base_url: &str,
333→) -> std::sync::mpsc::Receiver<anyhow::Result<Vec<DiscoveredModel>>> {
334→    let (tx, rx) = std::sync::mpsc::sync_channel(1);
335→    let base_url = base_url.to_string();
336→    std::thread::spawn(move || {
337→        let result = tokio::runtime::Builder::new_current_thread()
338→            .enable_all()
339→            .build()
340→            .map_err(anyhow::Error::from)
341→            .and_then(|rt| rt.block_on(discover_ollama_models_from_api(base_url)));
342→        let _ = tx.send(result);
343→    });
344→    rx
345→}
