349→#[derive(Debug, Default, serde::Deserialize)]
350→struct OllamaShowResponse {
351→    #[serde(default)]
352→    details: OllamaModelDetails,
353→    /// Ollama >= 0.5.x returns a list of model capabilities (e.g. `["tools"]`).
354→    #[serde(default)]
355→    capabilities: Vec<String>,
356→}
357→
358→#[derive(Debug, Clone, Default, serde::Deserialize)]
359→struct OllamaModelDetails {
360→    family: Option<String>,
361→    #[serde(default)]
362→    families: Option<Vec<String>>,
363→}
364→
365→/// Model families known to support native OpenAI-style tool calling in Ollama.
366→const OLLAMA_NATIVE_TOOL_FAMILIES: &[&str] = &[
367→    "llama3.1",
368→    "llama3.2",
369→    "llama3.3",
370→    "llama4",
371→    "qwen2.5",
372→    "qwen3",
373→    "mistral",
374→    "mixtral",
375→    "command-r",
376→    "firefunction",
377→    "hermes",
378→];
379→
380→/// Determine whether an Ollama model supports native tool calling based on its
381→/// model name and family metadata from `/api/show`.
382→fn ollama_model_supports_native_tools(model_name: &str, details: &OllamaModelDetails) -> bool {
383→    let name_lower = model_name.to_ascii_lowercase();
384→
385→    // Check all family strings from the model details.
386→    let families_iter = details
387→        .family
388→        .iter()
389→        .chain(details.families.iter().flatten());
390→    for family in families_iter {
391→        let fam_lower = family.to_ascii_lowercase();
392→        if OLLAMA_NATIVE_TOOL_FAMILIES
393→            .iter()
394→            .any(|known| fam_lower.contains(known))
395→        {
396→            return true;
397→        }
398→    }
399→

400→    // Heuristic: check model name for known families.
401→    OLLAMA_NATIVE_TOOL_FAMILIES
402→        .iter()
403→        .any(|known| name_lower.contains(known))
404→}
405→
406→/// Check if Ollama's `capabilities` list indicates native tool support.
407→///
408→/// Returns `Some(true)` if `"tools"` is present, `Some(false)` if capabilities
409→/// exist but don't include tools, and `None` if the list is empty (pre-0.5.x
410→/// Ollama versions that don't report capabilities).
411→fn ollama_capabilities_support_tools(capabilities: &[String]) -> Option<bool> {
412→    if capabilities.is_empty() {
413→        return None;
414→    }
415→    Some(capabilities.iter().any(|c| c == "tools"))
416→}
417→
418→/// Probe the Ollama `/api/show` endpoint for a specific model to get its family
419→/// and details. Returns `Ok(response)` on success, error on timeout/failure.
420→async fn probe_ollama_model_info(
421→    base_url: &str,
422→    model_name: &str,
423→) -> anyhow::Result<OllamaShowResponse> {
424→    let api_base = normalize_ollama_api_base_url(base_url);
425→    let endpoint = format!("{}/api/show", api_base.trim_end_matches('/'));
426→    let response = reqwest::Client::builder()
427→        .timeout(std::time::Duration::from_secs(3))
428→        .build()?
429→        .post(&endpoint)
430→        .json(&serde_json::json!({ "name": model_name }))
431→        .send()
432→        .await?;
433→
434→    let status = response.status();
435→    if !status.is_success() {
436→        anyhow::bail!("ollama /api/show for {model_name} failed HTTP {status}");
437→    }
438→    Ok(response.json().await?)
