441→/// Resolve the effective tool mode for an Ollama model.
442→///
443→/// - If the user configured an explicit `tool_mode`, use that.
444→/// - Otherwise, check the model's `capabilities` list from Ollama (>= 0.5.x).
445→/// - Fall back to the hardcoded family whitelist only when capabilities are
446→///   unavailable (pre-0.5.x Ollama).
447→fn resolve_ollama_tool_mode(
448→    config_tool_mode: moltis_config::ToolMode,
449→    model_name: &str,
450→    probe_result: Option<&OllamaShowResponse>,
451→) -> moltis_config::ToolMode {
452→    use moltis_config::ToolMode;
453→
454→    match config_tool_mode {
455→        ToolMode::Native | ToolMode::Text | ToolMode::Off => config_tool_mode,
456→        ToolMode::Auto => {
457→            // Prefer Ollama's own capabilities field when available.
458→            if let Some(resp) = probe_result
459→                && let Some(supports) = ollama_capabilities_support_tools(&resp.capabilities)
460→            {
461→                return if supports {
462→                    ToolMode::Native
463→                } else {
464→                    ToolMode::Text
465→                };
466→            }
467→            // Fallback: family whitelist (pre-0.5.x Ollama without capabilities).
468→            let details = probe_result
469→                .map(|r| &r.details)
470→                .cloned()
471→                .unwrap_or_default();
472→            if ollama_model_supports_native_tools(model_name, &details) {
473→                ToolMode::Native
474→            } else {
475→                ToolMode::Text
476→            }
477→        },
478→    }
479→}
