481→/// Batch-probe Ollama `/api/show` for a list of models.
482→/// Runs probes in a dedicated thread with its own tokio runtime (same pattern
483→/// as `discover_ollama_models`). Returns a map from model ID to show response;
484→/// failures are silently dropped.
485→fn probe_ollama_models_batch(
486→    base_url: &str,
487→    models: &[DiscoveredModel],
488→) -> HashMap<String, OllamaShowResponse> {
489→    if models.is_empty() {
490→        return HashMap::new();
491→    }
492→    let base_url = base_url.to_string();
493→    let model_ids: Vec<String> = models.iter().map(|m| m.id.clone()).collect();
494→    let (tx, rx) = std::sync::mpsc::sync_channel(1);
495→
496→    std::thread::spawn(move || {
497→        let result = tokio::runtime::Builder::new_current_thread()
498→            .enable_all()
499→            .build()
500→            .map(|rt| {
501→                rt.block_on(async {
502→                    let futs: Vec<_> = model_ids
503→                        .iter()
504→                        .map(|id| {
505→                            let base = base_url.clone();
506→                            let model_id = id.clone();
507→                            async move {
508→                                let resp = probe_ollama_model_info(&base, &model_id).await;
509→                                (model_id, resp)
510→                            }
511→                        })
512→                        .collect();
513→                    futures::future::join_all(futs).await
514→                })
515→            });
516→        let _ = tx.send(result);
517→    });
518→
519→    match rx.recv() {
520→        Ok(Ok(results)) => results
521→            .into_iter()
522→            .filter_map(|(id, r)| r.ok().map(|resp| (id, resp)))
523→            .collect(),
524→        _ => HashMap::new(),
525→    }
526→}
