 76→fn title_case_chunk(chunk: &str) -> String {
 77→    if chunk.is_empty() {
 78→        return String::new();
 79→    }
 80→    let mut chars = chunk.chars();
 81→    match chars.next() {
 82→        Some(first) => {
 83→            let mut out = String::new();
 84→            out.push(first.to_ascii_uppercase());
 85→            out.push_str(chars.as_str());
 86→            out
 87→        },
 88→        None => String::new(),
 89→    }
 90→}
