620→/// Return the known context window size (in tokens) for a model ID.
621→/// Falls back to 200,000 for unknown models.
622→pub fn context_window_for_model(model_id: &str) -> u32 {
623→    let model_id = capability_model_id(model_id);
624→    // Codestral has the largest window at 256k.
625→    if model_id.starts_with("codestral") {
626→        return 256_000;
627→    }
628→    // Claude models: 200k.
629→    if model_id.starts_with("claude-") {
630→        return 200_000;
631→    }
632→    // OpenAI o3/o4-mini: 200k.
633→    if model_id.starts_with("o3") || model_id.starts_with("o4-mini") {
634→        return 200_000;
635→    }
636→    // GPT-4o, GPT-4-turbo, GPT-5 series: 128k.
637→    if model_id.starts_with("gpt-4") || model_id.starts_with("gpt-5") {
638→        return 128_000;
639→    }
640→    // Mistral Large: 128k.
641→    if model_id.starts_with("mistral-large") {
642→        return 128_000;
643→    }
644→    // Gemini: 1M context.
645→    if model_id.starts_with("gemini-") {
646→        return 1_000_000;
647→    }
648→    // Kimi K2.5: 128k.
649→    if model_id.starts_with("kimi-") {
650→        return 128_000;
651→    }
652→    // MiniMax M2/M2.1/M2.5/M2.7: 204,800.
653→    if model_id.starts_with("MiniMax-") {
654→        return 204_800;
655→    }
656→    // Z.AI GLM-4-32B: 128k.
657→    if model_id == "glm-4-32b-0414-128k" {
658→        return 128_000;
659→    }
660→    // Z.AI GLM-5/4.7/4.6/4.5 series: 128k.
661→    if model_id.starts_with("glm-") {
662→        return 128_000;
663→    }
664→    // Default fallback.
665→    200_000
666→}
