668→/// Returns `false` for model IDs that are clearly not chat-completion models
669→/// (image generators, TTS, speech-to-text, embeddings, moderation, etc.).
670→///
671→/// Provider APIs like OpenAI's `/v1/models` return every model in the account.
672→/// Since no capability metadata is exposed we filter by well-known prefixes and
673→/// patterns. This is applied both at discovery time and at display time so that
674→/// non-chat models never appear in the UI.
675→pub fn is_chat_capable_model(model_id: &str) -> bool {
676→    let id = capability_model_id(model_id);
677→    const NON_CHAT_PREFIXES: &[&str] = &[
678→        "dall-e",
679→        "gpt-image",
680→        "chatgpt-image",
681→        "gpt-audio",
682→        "tts-",
683→        "whisper",
684→        "text-embedding",
685→        "omni-moderation",
686→        "moderation-",
687→        "sora",
688→        // Google Gemini non-chat models
689→        "imagen-",
690→        "gemini-embedding",
691→        "learnlm-",
692→        // Z.AI non-chat models
693→        "glm-image",
694→        "glm-asr",
695→        "glm-ocr",
696→        "cogvideo",
697→        "cogview",
698→        "vidu",
699→        "autoglm-phone",
700→    ];
701→    for prefix in NON_CHAT_PREFIXES {
702→        if id.starts_with(prefix) {
703→            return false;
704→        }
705→    }
706→    // TTS / audio-only / realtime / transcription variants
707→    if id.contains("-tts") || id.contains("-audio-") || id.ends_with("-audio") {
708→        return false;
709→    }
710→    if id.contains("-realtime-") || id.ends_with("-realtime") {
711→        return false;
712→    }
713→    if id.contains("-transcribe") {
714→        return false;
715→    }
716→    true
717→}
