719→/// Check if a model supports tool/function calling.
720→///
721→/// Most modern chat models support tools, but legacy completions-only models
722→/// (e.g. `babbage-002`, `davinci-002`) and non-chat models do not.
723→/// This is checked per-model rather than per-provider so that providers
724→/// exposing mixed catalogs report accurate tool support.
725→pub fn supports_tools_for_model(model_id: &str) -> bool {
726→    let id = capability_model_id(model_id);
727→    // Legacy completions-only models — no tool support
728→    if id.starts_with("babbage") || id.starts_with("davinci") {
729→        return false;
730→    }
731→    // Non-chat model families — never support tools
732→    if id.starts_with("dall-e")
733→        || id.starts_with("gpt-image")
734→        || id.starts_with("tts-")
735→        || id.starts_with("whisper")
736→        || id.starts_with("text-embedding")
737→        || id.starts_with("omni-moderation")
738→    {
739→        return false;
740→    }
741→    // Default: assume tool support for modern chat models
742→    true
743→}
744→
745→/// Check if a model supports vision (image inputs).
746→///
747→/// Vision-capable models can process images in tool results and user messages.
748→/// When true, the runner sends images as multimodal content blocks rather than
749→/// stripping them from the context.
750→pub fn supports_vision_for_model(model_id: &str) -> bool {
751→    let model_id = capability_model_id(model_id);
752→    // Claude models: all modern Claude models support vision
753→    if model_id.starts_with("claude-") {
754→        return true;
755→    }
756→    // GPT-4o and variants support vision
757→    if model_id.starts_with("gpt-4o") {
758→        return true;
759→    }
760→    // GPT-4 turbo supports vision
761→    if model_id.starts_with("gpt-4-turbo") {
762→        return true;
763→    }
764→    // GPT-5 series supports vision
765→    if model_id.starts_with("gpt-5") {
766→        return true;
767→    }
768→    // o3/o4 series supports vision
769→    if model_id.starts_with("o3") || model_id.starts_with("o4") {
770→        return true;
771→    }
772→    // Gemini models support vision
773→    if model_id.starts_with("gemini-") {
774→        return true;
775→    }
776→    // Z.AI GLM vision models
777→    if model_id.starts_with("glm-") && model_id.contains('v') {
778→        return true;
779→    }
780→    // Default: no vision support
781→    false
782→}
