1160→    fn resolve_registry_model_id(
1161→        &self,
1162→        model_id: &str,
1163→        provider_hint: Option<&str>,
1164→    ) -> Option<String> {
1165→        if self.providers.contains_key(model_id) {
1166→            return Some(model_id.to_string());
1167→        }
1168→
1169→        let raw = raw_model_id(model_id);
1170→        self.models
1171→            .iter()
1172→            .enumerate()
1173→            .filter(|(_, m)| raw_model_id(&m.id) == raw)
1174→            .filter(|(_, m)| provider_hint.is_none_or(|hint| m.provider == hint))
1175→            .min_by_key(|(idx, m)| (subscription_preference_rank(&m.provider), *idx))
1176→            .map(|(_, m)| m.id.clone())
1177→    }
