1204→    #[cfg(any(feature = "provider-openai-codex", feature = "provider-github-copilot"))]
1205→    fn register_dynamic_source_models(
1206→        &mut self,
1207→        source: &dyn DynamicModelDiscovery,
1208→        config: &ProvidersConfig,
1209→        catalog: Vec<DiscoveredModel>,
1210→    ) {
1211→        let Some(models) = Self::desired_models_for_dynamic_source(source, config, catalog) else {
1212→            return;
1213→        };
1214→
1215→        for model in models {
1216→            if self.has_provider_model(source.provider_name(), &model.id) {
1217→                continue;
1218→            }
1219→            let provider = source.build_provider(model.id.clone(), config);
1220→            self.register(
1221→                ModelInfo {
1222→                    id: model.id.clone(),
1223→                    provider: source.provider_name().to_string(),
1224→                    display_name: source.display_name(&model.id, &model.display_name),
1225→                    created_at: model.created_at,
1226→                },
1227→                provider,
1228→            );
1229→        }
1230→    }
1231→
1232→    #[cfg(any(feature = "provider-openai-codex", feature = "provider-github-copilot"))]
1233→    fn refresh_dynamic_source_models(
1234→        &mut self,
1235→        source: &dyn DynamicModelDiscovery,
1236→        config: &ProvidersConfig,
1237→    ) -> bool {
1238→        if !source.is_enabled_and_authenticated(config) {
1239→            return false;
1240→        }
1241→        if !source.should_fetch_models(config) {
1242→            return false;
1243→        }
1244→
1245→        let live_catalog = match source.live_models() {
1246→            Ok(models) => models,
1247→            Err(err) => {
1248→                tracing::warn!(
1249→                    provider = source.provider_name(),
1250→                    error = %err,
1251→                    "skipping dynamic model refresh because live fetch failed"
1252→                );
1253→                return false;
1254→            },
1255→        };
1256→
1257→        let Some(next_models) =
1258→            Self::desired_models_for_dynamic_source(source, config, live_catalog)
1259→        else {
1260→            return false;
1261→        };
1262→
1263→        let new_entries: Vec<(ModelInfo, Arc<dyn LlmProvider>)> = next_models
1264→            .into_iter()
1265→            .map(|model| {
1266→                (
1267→                    ModelInfo {
1268→                        id: model.id.clone(),
1269→                        provider: source.provider_name().to_string(),
1270→                        display_name: source.display_name(&model.id, &model.display_name),
1271→                        created_at: model.created_at,
1272→                    },
1273→                    source.build_provider(model.id, config),
1274→                )
1275→            })
1276→            .collect();
1277→
1278→        // Replace stale provider entries atomically only after successful fetch.
1279→        let stale_ids: Vec<String> = self
1280→            .models
1281→            .iter()
1282→            .filter(|m| m.provider == source.provider_name())
1283→            .map(|m| m.id.clone())
1284→            .collect();
1285→        for model_id in &stale_ids {
1286→            self.providers.remove(model_id);
1287→        }
1288→        self.models.retain(|m| m.provider != source.provider_name());
1289→        for (info, provider) in new_entries {
1290→            self.register(info, provider);
1291→        }
1292→
1293→        true
1294→    }
