1296→    /// Register a provider manually.
1297→    pub fn register(&mut self, mut info: ModelInfo, provider: Arc<dyn LlmProvider>) {
1298→        let model_id = raw_model_id(&info.id).to_string();
1299→        let registry_model_id = namespaced_model_id(&info.provider, &model_id);
1300→        info.id = registry_model_id.clone();
1301→        let wrapped: Arc<dyn LlmProvider> = Arc::new(RegistryModelProvider {
1302→            model_id: registry_model_id.clone(),
1303→            inner: provider,
1304→        });
1305→        self.providers.insert(registry_model_id, wrapped);
1306→        self.models.push(info);
1307→    }
