1309→    /// Unregister a provider by model ID. Returns true if it was removed.
1310→    pub fn unregister(&mut self, model_id: &str) -> bool {
1311→        let resolved_id = self.resolve_registry_model_id(model_id, None);
1312→        let removed = resolved_id
1313→            .as_deref()
1314→            .and_then(|id| self.providers.remove(id))
1315→            .is_some();
1316→        if removed && let Some(id) = resolved_id {
1317→            self.models.retain(|m| m.id != id);
1318→        }
1319→        removed
1320→    }
