1427→    /// Fire all provider model discovery HTTP requests concurrently.
1428→    ///
1429→    /// Returns a vec of `(provider_key, Receiver)` handles. Each receiver
1430→    /// will eventually yield the discovered model list. Call
1431→    /// [`collect_discoveries`] to drain them (blocking).
1432→    #[allow(unused_mut)] // `pending` may be unused when features are disabled
1433→    pub fn fire_discoveries(
1434→        config: &ProvidersConfig,
1435→        env_overrides: &HashMap<String, String>,
1436→    ) -> PendingDiscoveries {
1437→        let mut pending: PendingDiscoveries = Vec::new();
1438→
1439→        // ── OpenAI builtin ───────────────────────────────────────────────
1440→        if config.is_enabled("openai")
1441→            && !cfg!(test)
1442→            && let Some(key) = resolve_api_key(config, "openai", "OPENAI_API_KEY", env_overrides)
1443→            && should_fetch_models(config, "openai")
1444→        {
1445→            let base_url = config
1446→                .get("openai")
1447→                .and_then(|e| e.base_url.clone())
1448→                .or_else(|| env_value(env_overrides, "OPENAI_BASE_URL"))
1449→                .unwrap_or_else(|| "https://api.openai.com/v1".into());
1450→            pending.push((
1451→                "openai".into(),
1452→                openai::start_model_discovery(key.clone(), base_url),
1453→            ));
1454→        }
1455→
1456→        // ── OpenAI-compatible providers ──────────────────────────────────
1457→        for def in OPENAI_COMPAT_PROVIDERS {
1458→            if !config.is_enabled(def.config_name) {
1459→                continue;
1460→            }
1461→
1462→            let key = resolve_api_key(config, def.config_name, def.env_key, env_overrides);
1463→            let key = if !def.requires_api_key {
1464→                key.or_else(|| Some(secrecy::Secret::new(def.config_name.into())))
1465→            } else if def.config_name == "gemini" {
1466→                key.or_else(|| env_value(env_overrides, "GOOGLE_API_KEY").map(secrecy::Secret::new))
1467→            } else {
1468→                key
1469→            };
1470→
1471→            let Some(key) = key else {
1472→                continue;
1473→            };
1474→
1475→            let base_url = config
1476→                .get(def.config_name)
1477→                .and_then(|e| e.base_url.clone())
1478→                .or_else(|| env_value(env_overrides, def.env_base_url_key))
1479→                .unwrap_or_else(|| def.default_base_url.into());
1480→
1481→            let preferred = configured_models_for_provider(config, def.config_name);
1482→
1483→            if def.local_only {
1484→                let has_explicit_entry = config.get(def.config_name).is_some();
1485→                let has_env_base_url = env_value(env_overrides, def.env_base_url_key).is_some();
1486→                if !has_explicit_entry && !has_env_base_url && preferred.is_empty() {
1487→                    continue;
1488→                }
1489→            }
1490→
1491→            let skip_discovery = def.models.is_empty()
1492→                && preferred.is_empty()
1493→                && !def.local_only
1494→                && (def.config_name == "venice" || cfg!(test));
1495→            let user_opted_in = config
1496→                .get(def.config_name)
1497→                .is_some_and(|entry| entry.fetch_models);
1498→            let try_fetch = def.supports_model_discovery || user_opted_in;
1499→
1500→            if !skip_discovery && try_fetch && should_fetch_models(config, def.config_name) {
1501→                if def.config_name == "ollama" {
1502→                    pending.push((def.config_name.into(), start_ollama_discovery(&base_url)));
1503→                } else {
1504→                    pending.push((
1505→                        def.config_name.into(),
1506→                        openai::start_model_discovery(key.clone(), base_url),
1507→                    ));
1508→                }
1509→            }
1510→        }
1511→
1512→        // ── Custom providers ─────────────────────────────────────────────
1513→        for (name, entry) in &config.providers {
1514→            if !name.starts_with("custom-") || !entry.enabled {
1515→                continue;
1516→            }
1517→            let Some(api_key) = entry
1518→                .api_key
1519→                .as_ref()
1520→                .filter(|k| !k.expose_secret().is_empty())
1521→            else {
1522→                continue;
1523→            };
1524→            let Some(base_url) = entry.base_url.as_ref().filter(|u| !u.trim().is_empty()) else {
1525→                continue;
1526→            };
1527→            if should_fetch_models(config, name) {
1528→                pending.push((
1529→                    name.clone(),
1530→                    openai::start_model_discovery(api_key.clone(), base_url.clone()),
1531→                ));
1532→            }
1533→        }
1534→
1535→        // ── OpenAI Codex ─────────────────────────────────────────────────
1536→        #[cfg(feature = "provider-openai-codex")]
1537→        if oauth_discovery_enabled(config, "openai-codex")
1538→            && openai_codex::has_stored_tokens()
1539→            && should_fetch_models(config, "openai-codex")
1540→            && let Some(rx) = openai_codex::start_model_discovery()
1541→        {
1542→            pending.push(("openai-codex".into(), rx));
1543→        }
1544→
1545→        // ── GitHub Copilot ───────────────────────────────────────────────
1546→        #[cfg(feature = "provider-github-copilot")]
1547→        if oauth_discovery_enabled(config, "github-copilot")
1548→            && github_copilot::has_stored_tokens()
1549→            && should_fetch_models(config, "github-copilot")
1550→        {
1551→            pending.push((
1552→                "github-copilot".into(),
1553→                github_copilot::start_model_discovery(),
1554→            ));
1555→        }
1556→
1557→        pending
1558→    }
1559→
1560→    /// Drain all pending discovery receivers (blocking on each `recv()`).
1561→    ///
1562→    /// Returns a map from provider name to discovered models.
1563→    pub fn collect_discoveries(
1564→        pending: PendingDiscoveries,
1565→    ) -> HashMap<String, Vec<DiscoveredModel>> {
1566→        let mut results: HashMap<String, Vec<DiscoveredModel>> = HashMap::new();
1567→        for (key, rx) in pending {
1568→            match rx.recv() {
1569→                Ok(Ok(models)) => {
1570→                    tracing::debug!(
1571→                        provider = %key,
1572→                        model_count = models.len(),
1573→                        "parallel model discovery succeeded"
1574→                    );
1575→                    results.insert(key, models);
1576→                },
1577→                Ok(Err(err)) => {
1578→                    let msg = err.to_string();
1579→                    if msg.contains("not logged in")
1580→                        || msg.contains("tokens not found")
1581→                        || msg.contains("not configured")
1582→                    {
1583→                        tracing::debug!(
1584→                            provider = %key,
1585→                            error = %err,
1586→                            "provider not configured, skipping model discovery"
1587→                        );
1588→                    } else {
1589→                        tracing::warn!(
1590→                            provider = %key,
1591→                            error = %err,
1592→                            "parallel model discovery failed"
1593→                        );
1594→                    }
1595→                },
1596→                Err(err) => {
1597→                    tracing::warn!(
1598→                        provider = %key,
1599→                        error = %err,
1600→                        "parallel model discovery worker crashed"
1601→                    );
1602→                },
1603→            }
1604→        }
1605→        results
1606→    }
