251→const OPENAI_MAX_TOOL_CALL_ID_LEN: usize = 40;
252→
253→fn short_stable_hash(value: &str) -> String {
254→    use std::hash::{Hash, Hasher};
255→
256→    let mut hasher = std::collections::hash_map::DefaultHasher::new();
257→    value.hash(&mut hasher);
258→    format!("{:016x}", hasher.finish())
259→}
260→
261→fn base_openai_tool_call_id(raw: &str) -> String {
262→    let mut cleaned: String = raw
263→        .chars()
264→        .map(|ch| {
265→            if ch.is_ascii_alphanumeric() || matches!(ch, '_' | '-') {
266→                ch
267→            } else {
268→                '_'
269→            }
270→        })
271→        .collect();
272→
273→    if cleaned.is_empty() {
274→        cleaned = "call".to_string();
275→    }
276→
277→    if cleaned.len() <= OPENAI_MAX_TOOL_CALL_ID_LEN {
278→        return cleaned;
279→    }
280→
281→    let hash = short_stable_hash(raw);
282→    let keep = OPENAI_MAX_TOOL_CALL_ID_LEN.saturating_sub(hash.len() + 1);
283→    cleaned.truncate(keep);
284→    if cleaned.is_empty() {
285→        return format!("call-{hash}");
286→    }
287→    format!("{cleaned}-{hash}")
288→}
289→
290→fn disambiguate_tool_call_id(base: &str, nonce: usize) -> String {
291→    let suffix = format!("-{nonce}");
292→    let keep = OPENAI_MAX_TOOL_CALL_ID_LEN.saturating_sub(suffix.len());
293→
294→    let mut value = base.to_string();
295→    if value.len() > keep {
296→        value.truncate(keep);
297→    }
298→    if value.is_empty() {
299→        value = "call".to_string();
300→        if value.len() > keep {
301→            value.truncate(keep);
302→        }
303→    }
304→    format!("{value}{suffix}")
305→}
