307→fn assign_openai_tool_call_id(
308→    raw: &str,
309→    remapped_tool_call_ids: &mut HashMap<String, String>,
310→    used_tool_call_ids: &mut HashSet<String>,
311→) -> String {
312→    if let Some(existing) = remapped_tool_call_ids.get(raw) {
313→        return existing.clone();
314→    }
315→
316→    let base = base_openai_tool_call_id(raw);
317→    let mut candidate = base.clone();
318→    let mut nonce = 1usize;
319→    while used_tool_call_ids.contains(&candidate) {
320→        candidate = disambiguate_tool_call_id(&base, nonce);
321→        nonce = nonce.saturating_add(1);
322→    }
323→
324→    used_tool_call_ids.insert(candidate.clone());
325→    remapped_tool_call_ids.insert(raw.to_string(), candidate.clone());
326→    candidate
327→}
