 66→    /// Apply `thinking` configuration to an Anthropic request body based on
 67→    /// the configured reasoning effort.
 68→    fn apply_thinking(&self, body: &mut serde_json::Value) {
 69→        use moltis_agents::model::ReasoningEffort;
 70→        let Some(effort) = self.reasoning_effort else {
 71→            return;
 72→        };
 73→        let budget_tokens: u64 = match effort {
 74→            ReasoningEffort::Low => 4096,
 75→            ReasoningEffort::Medium => 10240,
 76→            ReasoningEffort::High => 32768,
 77→        };
 78→        body["thinking"] = serde_json::json!({
 79→            "type": "enabled",
 80→            "budget_tokens": budget_tokens,
 81→        });
 82→        // Extended thinking requires higher max_tokens than budget_tokens.
 83→        if let Some(max_tokens) = body["max_tokens"].as_u64()
 84→            && max_tokens <= budget_tokens
 85→        {
 86→            body["max_tokens"] = serde_json::json!(budget_tokens + 4096);
 87→        }
 88→    }
