    #[test]
    fn openai_provider_supports_tools_respects_override() {
        use moltis_config::ToolMode;
        let make = |mode: ToolMode| {
            openai::OpenAiProvider::new(secret("key"), "gpt-4o".into(), "http://x".into())
                .with_tool_mode(mode)
